  1	//! RTK Token Compression — deterministic tool_result block filters.
  2	//!
  3	//! Port of 9router's RTK Token Saver: auto-compresses `tool_result` content
  4	//! before forwarding to the LLM, saving 20–40% input tokens per request.
  5	//!
  6	//! ## Design
  7	//! - **Auto-detect**: peek at the first 1KB of content, pick the best filter.
  8	//! - **11 filters**: git-diff, git-status, grep, find, ls, tree, dedup-log,
  9	//!   smart-truncate, read-numbered, search-list, build-output.
 10	//! - **Fail-safe**: never returns empty, never grows input.
 11	//! - **PII-safe**: deterministic string transforms, no ML, no external calls.
 12	//! - **<1ms**: pure string processing, no allocations beyond the output buffer.
 13	//!
 14	//! ## Integration
 15	//! The proxy calls [`compress_tool_results`] on the request body before
 16	//! forwarding to the provider. Gated per-tenant via entitlement.
 17	
 18	/// The detection window for auto-picking a filter (first 1KB).
 19	const PEEK_BYTES: usize = 1024;
 20	
 21	/// Maximum output size — if compression doesn't shrink, return original.
 22	const MAX_COMPRESSION_RATIO: f64 = 0.95;
 23	
 24	/// Available compression filters, auto-detected from content.
 25	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 26	pub enum Filter {
 27	    /// `git diff` output — collapse unchanged context lines, keep hunks.
 28	    GitDiff,
 29	    /// `git status` output — collapse verbose untracked listings.
 30	    GitStatus,
 31	    /// `grep` output — deduplicate file-level matches, keep first N per file.
 32	    Grep,
 33	    /// `find` output — collapse deep directory listings.
 34	    Find,
 35	    /// `ls` output — collapse long directory listings.
 36	    Ls,
 37	    /// `tree` output — prune deep subtrees, keep top N levels.
 38	    Tree,
 39	    /// Repetitive log output — deduplicate consecutive identical blocks.
 40	    DedupLog,
 41	    /// Generic smart truncation — keep first + last N lines of long output.
 42	    SmartTruncate,
 43	    /// Numbered file content (`cat -n` / Read tool) — collapse unchanged regions.
 44	    ReadNumbered,
 45	    /// Search result lists — collapse to summary + top results.
 46	    SearchList,
 47	    /// Build/compile output — collapse per-file compilation lines, keep errors.
 48	    BuildOutput,
 49	}
