 51	/// Detect the best filter for the given content by peeking at the first
 52	/// [`PEEK_BYTES`] bytes. Returns `None` if no filter matches (content is
 53	/// not a recognized tool_result pattern).
 54	pub fn detect_filter(content: &str) -> Option<Filter> {
 55	    let peek = if content.len() > PEEK_BYTES {
 56	        // Floor to the largest char boundary <= PEEK_BYTES. Slicing at a raw
 57	        // byte offset panics if it lands inside a multi-byte UTF-8 character
 58	        // (e.g. Hindi/CJK/emoji/em-dash straddling byte 1024) — a reachable
 59	        // panic on the chat hot path. `str::floor_char_boundary` is unstable on
 60	        // the pinned Rust 1.86, so walk back manually (byte 0 is always a
 61	        // boundary, so this always terminates).
 62	        let mut end = PEEK_BYTES;
 63	        while !content.is_char_boundary(end) {
 64	            end -= 1;
 65	        }
 66	        &content[..end]
 67	    } else {
 68	        content
 69	    };
 70	
 71	    // Order matters — more specific patterns first.
 72	    if peek.starts_with("diff --git") || peek.contains("@@ ") && peek.contains("+++") {
 73	        Some(Filter::GitDiff)
 74	    } else if peek.starts_with("On branch ") || peek.contains("Changes not staged") {
 75	        Some(Filter::GitStatus)
 76	    } else if peek.contains("warning[") || peek.contains("error[E") || peek.contains("Compiling ") {
 77	        Some(Filter::BuildOutput)
 78	    } else if peek
 79	        .lines()
 80	        .take(5)
 81	        .any(|l| l.starts_with("   1\t") || l.starts_with("     1\t"))
 82	    {
 83	        Some(Filter::ReadNumbered)
 84	    } else if peek
 85	        .lines()
 86	        .take(5)
 87	        .any(|l| l.contains(':') && l.contains(" match"))
 88	    {
 89	        Some(Filter::Grep)
 90	    } else if peek.starts_with(".")
 91	        || peek
 92	            .lines()
 93	            .take(10)
 94	            .all(|l| l.starts_with("./") || l.starts_with('/'))
 95	    {
 96	        Some(Filter::Find)
 97	    } else if peek.contains("├──") || peek.contains("└──") || peek.contains("│") {
 98	        Some(Filter::Tree)
 99	    } else if peek
100	        .lines()
101	        .take(5)
102	        .any(|l| l.starts_with("total ") || l.starts_with("-rw") || l.starts_with("drwx"))
103	    {
104	        Some(Filter::Ls)
105	    } else if peek.lines().count() > 50 && has_repetitive_blocks(peek) {
106	        Some(Filter::DedupLog)
107	    } else if content.lines().count() >= 60 {
108	        Some(Filter::SmartTruncate)
109	    } else {
110	        None
111	    }
112	}
