114	/// Compress tool_result content using auto-detected filter. Returns the
115	/// compressed string, or the original if compression doesn't help.
116	///
117	/// **Fail-safe guarantees:**
118	/// - Never returns empty string (returns original if compression yields empty).
119	/// - Never returns a string longer than the input.
120	/// - If detected filter produces output > [`MAX_COMPRESSION_RATIO`] of input,
121	///   returns original.
122	pub fn compress(content: &str) -> String {
123	    if content.len() < 256 {
124	        // Too short to benefit from compression.
125	        return content.to_string();
126	    }
127	
128	    match detect_filter(content) {
129	        Some(filter) => {
130	            let compressed = apply_filter(filter, content);
131	            // Fail-safe: never empty, never longer.
132	            if compressed.is_empty()
133	                || compressed.len() >= content.len()
134	                || (compressed.len() as f64 / content.len() as f64) > MAX_COMPRESSION_RATIO
135	            {
136	                content.to_string()
137	            } else {
138	                compressed
139	            }
140	        }
141	        None => content.to_string(),
142	    }
143	}
