145	/// Compress all tool_result text blocks in a chat message's content array.
146	/// This is the main entry point for the proxy — it processes the request
147	/// body's messages, finding tool_result content blocks and compressing them.
148	///
149	/// Returns the number of bytes saved across all compressed blocks.
150	pub fn compress_tool_results(messages_json: &mut serde_json::Value) -> usize {
151	    let mut saved = 0;
152	
153	    if let Some(messages) = messages_json
154	        .get_mut("messages")
155	        .and_then(|m| m.as_array_mut())
156	    {
157	        for msg in messages.iter_mut() {
158	            if msg.get("role").and_then(|r| r.as_str()) == Some("tool") {
159	                // Compress the content field (string or array of text blocks).
160	                if let Some(content) = msg.get_mut("content") {
161	                    if let Some(text) = content.as_str() {
162	                        let compressed = compress(text);
163	                        if compressed.len() < text.len() {
164	                            saved += text.len() - compressed.len();
165	                            *content = serde_json::Value::String(compressed);
166	                        }
167	                    } else if let Some(blocks) = content.as_array_mut() {
168	                        for block in blocks.iter_mut() {
169	                            if block.get("type").and_then(|t| t.as_str()) == Some("text") {
170	                                if let Some(text) = block.get_mut("text").and_then(|t| t.as_str()) {
171	                                    let text_owned = text.to_string();
172	                                    let compressed = compress(&text_owned);
173	                                    if compressed.len() < text_owned.len() {
174	                                        saved += text_owned.len() - compressed.len();
175	                                        block["text"] = serde_json::Value::String(compressed);
176	                                    }
177	                                }
178	                            }
179	                        }
180	                    }
181	                }
182	            }
183	        }
184	    }
185	
186	    saved
187	}
