189	fn apply_filter(filter: Filter, content: &str) -> String {
190	    match filter {
191	        Filter::GitDiff => compress_git_diff(content),
192	        Filter::GitStatus => compress_git_status(content),
193	        Filter::Grep => compress_grep(content),
194	        Filter::Find => compress_find(content),
195	        Filter::Ls => compress_ls(content),
196	        Filter::Tree => compress_tree(content),
197	        Filter::DedupLog => compress_dedup_log(content),
198	        Filter::SmartTruncate => compress_smart_truncate(content),
199	        Filter::ReadNumbered => compress_read_numbered(content),
200	        Filter::SearchList => compress_search_list(content),
201	        Filter::BuildOutput => compress_build_output(content),
202	    }
203	}
