209	/// Collapse unchanged context lines in git diff, keep only hunk headers and
210	/// changed lines (+/-). Limit context to 1 line around changes.
211	fn compress_git_diff(content: &str) -> String {
212	    let mut out = String::with_capacity(content.len() / 2);
213	    let mut last_was_context = false;
214	    let mut skipped_context = 0usize;
215	
216	    for line in content.lines() {
217	        if line.starts_with("diff --git")
218	            || line.starts_with("+++")
219	            || line.starts_with("---")
220	            || line.starts_with("@@")
221	            || line.starts_with('+')
222	            || line.starts_with('-')
223	        {
224	            // Header or changed line — always keep, flush any skipped context.
225	            if skipped_context > 0 {
226	                out.push_str(&format!(
227	                    "  ... ({skipped_context} context lines omitted)\n"
228	                ));
229	                skipped_context = 0;
230	            }
231	            out.push_str(line);
232	            out.push('\n');
233	            last_was_context = false;
234	        } else if line.starts_with(' ') {
235	            // Context line — keep first one after a change, skip the rest.
236	            if !last_was_context {
237	                out.push_str(line);
238	                out.push('\n');
239	                last_was_context = true;
240	            } else {
241	                skipped_context += 1;
242	            }
243	        } else {
244	            out.push_str(line);
245	            out.push('\n');
246	            last_was_context = false;
247	        }
248	    }
249	    if skipped_context > 0 {
250	        out.push_str(&format!(
251	            "  ... ({skipped_context} context lines omitted)\n"
252	        ));
253	    }
254	    out
255	}
