257	/// Collapse verbose untracked file listings in git status.
258	fn compress_git_status(content: &str) -> String {
259	    let mut out = String::with_capacity(content.len() / 2);
260	    // Whether we are inside the `Untracked files:` section, and how many
261	    // tab-indented untracked files we have seen so far within it. The old
262	    // logic only incremented the counter once it was already > 5, so it never
263	    // rose past the header's initial value and the collapse never fired.
264	    let mut in_untracked = false;
265	    let mut untracked_count = 0usize;
266	
267	    for line in content.lines() {
268	        // A tab-indented line inside the section is an untracked file: keep the
269	        // first 5, count the rest for the summary.
270	        if in_untracked && line.starts_with('\t') {
271	            untracked_count += 1;
272	            if untracked_count <= 5 {
273	                out.push_str(line);
274	                out.push('\n');
275	            }
276	            continue;
277	        }
278	
279	        // Any other line: the space-indented hint ("  (use \"git add ...\")")
280	        // stays part of the section; a blank or non-indented line ends it, so
281	        // flush the summary for the collapsed remainder first.
282	        if in_untracked && !line.starts_with(' ') {
283	            if untracked_count > 5 {
284	                out.push_str(&format!(
285	                    "\t... ({} more untracked files)\n",
286	                    untracked_count - 5
287	                ));
288	            }
289	            in_untracked = false;
290	            untracked_count = 0;
291	        }
292	
293	        out.push_str(line);
294	        out.push('\n');
295	        if line == "Untracked files:" {
296	            in_untracked = true; // Start counting after the header.
297	            untracked_count = 0;
298	        }
299	    }
300	
301	    // Flush if the input ended while still inside the untracked section.
302	    if in_untracked && untracked_count > 5 {
303	        out.push_str(&format!(
304	            "\t... ({} more untracked files)\n",
305	            untracked_count - 5
306	        ));
307	    }
308	    out
309	}
