311	/// Deduplicate grep matches — keep first 5 matches per file, summarize rest.
312	fn compress_grep(content: &str) -> String {
313	    let mut out = String::with_capacity(content.len() / 2);
314	    let mut current_file = String::new();
315	    let mut matches_in_file = 0usize;
316	    let mut skipped = 0usize;
317	
318	    for line in content.lines() {
319	        if let Some(file) = line.split(':').next() {
320	            if file != current_file {
321	                if skipped > 0 {
322	                    out.push_str(&format!(
323	                        "  ... ({skipped} more matches in {current_file})\n"
324	                    ));
325	                }
326	                current_file = file.to_string();
327	                matches_in_file = 0;
328	                skipped = 0;
329	            }
330	        }
331	        if matches_in_file < 5 {
332	            out.push_str(line);
333	            out.push('\n');
334	            matches_in_file += 1;
335	        } else {
336	            skipped += 1;
337	        }
338	    }
339	    if skipped > 0 {
340	        out.push_str(&format!(
341	            "  ... ({skipped} more matches in {current_file})\n"
342	        ));
343	    }
344	    out
345	}
