389	/// Prune deep subtrees — keep top 4 levels, collapse deeper.
390	fn compress_tree(content: &str) -> String {
391	    let mut out = String::with_capacity(content.len() / 2);
392	    let mut skipped = 0usize;
393	
394	    for line in content.lines() {
395	        // Count indentation depth (tree uses 4-space or box-drawing indentation).
396	        let depth = line
397	            .chars()
398	            .take_while(|c| *c == ' ' || *c == '│' || *c == '├' || *c == '└' || *c == '─')
399	            .count()
400	            / 4;
401	        if depth <= 4 || line.contains("directories") || line.contains("files") {
402	            if skipped > 0 {
403	                out.push_str(&format!("    ... ({skipped} items pruned)\n"));
404	                skipped = 0;
405	            }
406	            out.push_str(line);
407	            out.push('\n');
408	        } else {
409	            skipped += 1;
410	        }
411	    }
412	    if skipped > 0 {
413	        out.push_str(&format!("    ... ({skipped} items pruned)\n"));
414	    }
415	    out
416	}
