418	/// Deduplicate consecutive identical or near-identical log blocks.
419	fn compress_dedup_log(content: &str) -> String {
420	    let lines: Vec<&str> = content.lines().collect();
421	    let mut out = String::with_capacity(content.len() / 2);
422	    let mut last_line = "";
423	    let mut repeat_count = 0usize;
424	
425	    for line in &lines {
426	        if *line == last_line {
427	            repeat_count += 1;
428	        } else {
429	            if repeat_count > 2 {
430	                out.push_str(&format!("  ... (repeated {repeat_count} times)\n"));
431	            } else {
432	                for _ in 0..repeat_count {
433	                    out.push_str(last_line);
434	                    out.push('\n');
435	                }
436	            }
437	            out.push_str(line);
438	            out.push('\n');
439	            last_line = line;
440	            repeat_count = 0;
441	        }
442	    }
443	    // Final flush: mirror the in-loop branch so a run of 1–2 trailing repeats
444	    // is re-emitted instead of being silently dropped (only the > 2 case was
445	    // handled before, so a log ending in "OK\nOK" lost the duplicate).
446	    if repeat_count > 2 {
447	        out.push_str(&format!("  ... (repeated {repeat_count} times)\n"));
448	    } else {
449	        for _ in 0..repeat_count {
450	            out.push_str(last_line);
451	            out.push('\n');
452	        }
453	    }
454	    out
455	}
