462	    }
463	    let mut out = String::with_capacity(content.len() / 3);
464	    for line in &lines[..30] {
465	        out.push_str(line);
466	        out.push('\n');
467	    }
468	    out.push_str(&format!(
469	        "\n... ({} lines omitted — {} total lines)\n\n",
470	        lines.len() - 50,
471	        lines.len()
472	    ));
473	    for line in &lines[lines.len() - 20..] {
474	        out.push_str(line);
475	        out.push('\n');
476	    }
477	    out
