480	/// Collapse unchanged regions in numbered file content — keep first 10 +
481	/// last 10 lines, summarize middle.
482	fn compress_read_numbered(content: &str) -> String {
483	    let lines: Vec<&str> = content.lines().collect();
484	    if lines.len() <= 30 {
485	        return content.to_string();
486	    }
487	    let mut out = String::with_capacity(content.len() / 3);
488	    for line in &lines[..10] {
489	        out.push_str(line);
490	        out.push('\n');
491	    }
492	    out.push_str(&format!("  ... ({} lines omitted)\n", lines.len() - 20));
493	    for line in &lines[lines.len() - 10..] {
494	        out.push_str(line);
495	        out.push('\n');
496	    }
497	    out
498	}
