500	/// Collapse search result lists — keep summary + top 10 results.
501	fn compress_search_list(content: &str) -> String {
502	    let lines: Vec<&str> = content.lines().collect();
503	    if lines.len() <= 15 {
504	        return content.to_string();
505	    }
506	    let mut out = String::with_capacity(content.len() / 3);
507	    for line in &lines[..12] {
508	        out.push_str(line);
509	        out.push('\n');
510	    }
511	    out.push_str(&format!(
512	        "... ({} more results omitted)\n",
513	        lines.len() - 12
514	    ));
515	    out
516	}
