518	/// Collapse per-file compilation lines, keep errors and warnings.
519	fn compress_build_output(content: &str) -> String {
520	    let mut out = String::with_capacity(content.len() / 2);
521	    let mut compiling_count = 0usize;
522	
523	    for line in content.lines() {
524	        if line.starts_with("   Compiling ") || line.starts_with("   Downloading ") {
525	            compiling_count += 1;
526	        } else {
527	            if compiling_count > 3 {
528	                out.push_str(&format!("   ... ({compiling_count} crates compiled)\n"));
529	            } else {
530	                for _ in 0..compiling_count {
531	                    out.push_str("   Compiling ...\n");
532	                }
533	            }
534	            compiling_count = 0;
535	            out.push_str(line);
536	            out.push('\n');
537	        }
538	    }
539	    if compiling_count > 3 {
540	        out.push_str(&format!("   ... ({compiling_count} crates compiled)\n"));
541	    }
542	    out
543	}
