545	/// Check if content has repetitive blocks (consecutive similar lines).
546	fn has_repetitive_blocks(peek: &str) -> bool {
547	    let lines: Vec<&str> = peek.lines().collect();
548	    if lines.len() < 10 {
549	        return false;
550	    }
551	    let mut repeats = 0;
552	    for i in 1..lines.len() {
553	        if lines[i] == lines[i - 1] {
554	            repeats += 1;
555	        }
556	    }
557	    repeats > lines.len() / 4
558	}
