 30	/// A lock-free circuit breaker. All state lives in atomics, so checking and
 31	/// updating a provider's health never takes a mutex on the request hot path.
 32	///
 33	/// Closed -> (failure_threshold consecutive failures) -> Open
 34	/// Open    -> (cooldown elapsed) -> HalfOpen
 35	/// HalfOpen-> (success_threshold successes) -> Closed
 36	/// HalfOpen-> (any failure) -> Open
 37	pub struct CircuitBreaker {
 38	    state: AtomicU8, // 0=closed, 1=half-open, 2=open
 39	    failures: AtomicU64,
 40	    successes: AtomicU64,
 41	    opened_at: AtomicU64, // unix millis when opened
 42	    failure_threshold: u64,
 43	    success_threshold: u64,
 44	    cooldown_ms: u64,
 45	    now: Box<dyn Fn() -> u64 + Send + Sync>, // injectable clock (unix millis)
 46	}
 47	
 48	impl CircuitBreaker {
 49	    pub fn new() -> Self {
 50	        Self::with_config(
 51	            DEFAULT_FAILURE_THRESHOLD,
 52	            DEFAULT_SUCCESS_THRESHOLD,
 53	            DEFAULT_COOLDOWN_MS,
 54	        )
 55	    }
 56	
 57	    pub fn with_config(failure_threshold: u64, success_threshold: u64, cooldown_ms: u64) -> Self {
 58	        Self::with_clock(
 59	            failure_threshold,
 60	            success_threshold,
 61	            cooldown_ms,
 62	            Box::new(now_millis),
 63	        )
 64	    }
 65	
 66	    /// Construct with an injectable clock — used by tests to drive the cooldown
 67	    /// transition deterministically (no sleeps, no flake).
 68	    pub fn with_clock(
 69	        failure_threshold: u64,
 70	        success_threshold: u64,
 71	        cooldown_ms: u64,
 72	        now: Box<dyn Fn() -> u64 + Send + Sync>,
 73	    ) -> Self {
 74	        Self {
 75	            state: AtomicU8::new(0),
 76	            failures: AtomicU64::new(0),
 77	            successes: AtomicU64::new(0),
 78	            opened_at: AtomicU64::new(0),
 79	            failure_threshold,
 80	            success_threshold,
 81	            cooldown_ms,
 82	            now,
 83	        }
 84	    }
 85	
 86	    /// Current state, applying the cooldown transition (Open -> HalfOpen) on read.
 87	    /// Reading self-heals an expired breaker so the next request gets a trial.
 88	    pub fn state(&self) -> CircuitState {
 89	        let raw = self.state.load(Ordering::Acquire);
 90	        if raw == 2
 91	            && (self.now)().saturating_sub(self.opened_at.load(Ordering::Acquire))
 92	                >= self.cooldown_ms
 93	        {
 94	            // CAS so exactly one thread flips Open -> HalfOpen. ONLY the winner
 95	            // resets the trial-success counter and reports HalfOpen. A losing
 96	            // thread (another already flipped, or a trial has since closed/
 97	            // reopened the breaker) must NOT blindly wipe successes a completed
 98	            // trial may already have recorded, nor report a stale HalfOpen — it
 99	            // re-reads the live state below.
100	            if self
101	                .state
102	                .compare_exchange(2, 1, Ordering::AcqRel, Ordering::Acquire)
103	                .is_ok()
104	            {
105	                self.successes.store(0, Ordering::Release);
106	                return CircuitState::HalfOpen;
107	            }
108	            return match self.state.load(Ordering::Acquire) {
109	                0 => CircuitState::Closed,
110	                1 => CircuitState::HalfOpen,
111	                _ => CircuitState::Open,
112	            };
113	        }
114	        match raw {
115	            0 => CircuitState::Closed,
116	            1 => CircuitState::HalfOpen,
117	            _ => CircuitState::Open,
118	        }
119	    }
120	
121	    /// Whether a request may be attempted, IGNORING half-open concurrency
122	    /// (Closed or HalfOpen). The half-open probe cap lives in [`Self::admits`],
123	    /// which the [`HealthTracker`] applies with the live in-flight trial count;
124	    /// this bare check is the concurrency-agnostic view used for diagnostics.
125	    pub fn is_available(&self) -> bool {
126	        self.state() != CircuitState::Open
127	    }
128	
129	    /// Whether a request may be ADMITTED given `in_flight_trials` currently
130	    /// outstanding against this provider. Closed always admits; Open never does;
131	    /// HalfOpen admits only while fewer than `success_threshold` trials are in
132	    /// flight — a lock-free concurrency cap so a still-down provider is not
133	    /// funnelled full traffic during its half-open window (the reopen signal only
134	    /// arrives when a trial fails, which for a hard-down provider takes a whole
135	    /// attempt-timeout to materialize).
136	    ///
137	    /// The cap is SOFT: a caller reads the trial count, then dispatches (and only
138	    /// then increments the gauge), so a burst can momentarily overshoot the
139	    /// threshold. It is nonetheless self-correcting and leak-proof — once the
140	    /// gauge reaches the threshold new arrivals fail over, and the first failed
141	    /// trial reopens the breaker ([`Self::record_failure`]) — which is what sheds
142	    /// the load the pre-cap breaker never did. A HARD cap needs a probe permit
143	    /// held across the dispatch at the call site (the proxy attempt loop).
144	    pub fn admits(&self, in_flight_trials: u64) -> bool {
145	        match self.state() {
146	            CircuitState::Closed => true,
147	            CircuitState::Open => false,
148	            CircuitState::HalfOpen => in_flight_trials < self.success_threshold,
149	        }
150	    }
151	
152	    pub fn record_success(&self) {
153	        match self.state.load(Ordering::Acquire) {
154	            1 => {
155	                let s = self.successes.fetch_add(1, Ordering::AcqRel) + 1;
156	                if s >= self.success_threshold {
157	                    self.close();
158	                }
159	            }
160	            _ => {
161	                // Closed: a success resets the consecutive-failure count.
162	                self.failures.store(0, Ordering::Release);
163	            }
164	        }
165	    }
166	
167	    pub fn record_failure(&self) {
168	        match self.state.load(Ordering::Acquire) {
169	            1 => self.open(), // a half-open trial failed -> reopen
170	            _ => {
171	                let f = self.failures.fetch_add(1, Ordering::AcqRel) + 1;
172	                if f >= self.failure_threshold {
173	                    self.open();
174	                }
175	            }
176	        }
177	    }
178	
179	    fn open(&self) {
180	        self.state.store(2, Ordering::Release);
181	        self.opened_at.store((self.now)(), Ordering::Release);
182	        self.successes.store(0, Ordering::Release);
183	    }
184	
185	    fn close(&self) {
186	        self.state.store(0, Ordering::Release);
187	        self.failures.store(0, Ordering::Release);
188	        self.successes.store(0, Ordering::Release);
189	    }
190	}
