198	/// EWMA smoothing factor for latency, in 1/1000ths. The new sample is weighted
199	/// `LATENCY_ALPHA_MILLI / 1000`, the prior EWMA the remainder. 0.2 reacts to
200	/// shifts within a handful of samples without over-weighting a single spike.
201	const LATENCY_ALPHA_MILLI: u64 = 200;
202	
203	/// Sentinel meaning "no latency sample recorded yet" for the atomic EWMA store.
204	/// `u64::MAX` ms is unreachable as a real observation, so it can't collide with
205	/// a measured value.
206	const LATENCY_UNSET: u64 = u64::MAX;
207	
208	/// A lock-free exponentially-weighted moving average of observed latency, in
209	/// whole milliseconds, stored in a single atomic — same spirit as
210	/// `CircuitBreaker`: no mutex on the request hot path.
211	///
212	/// `record` folds each new sample in with a CAS loop; `read` returns `None`
213	/// until the first sample lands, so the latency strategy can treat untried
214	/// providers optimistically.
215	struct LatencyEwma {
216	    ewma_ms: AtomicU64,
217	}
218	
219	impl LatencyEwma {
220	    fn new() -> Self {
221	        Self {
222	            ewma_ms: AtomicU64::new(LATENCY_UNSET),
223	        }
224	    }
225	
226	    /// Fold a new latency sample into the EWMA. Lock-free via a CAS retry loop;
227	    /// contention here is negligible (one update per completed provider call).
228	    fn record(&self, sample_ms: u64) {
229	        loop {
230	            let prior = self.ewma_ms.load(Ordering::Acquire);
231	            let next = if prior == LATENCY_UNSET {
232	                sample_ms // first sample seeds the average
233	            } else {
234	                // ewma = alpha*sample + (1-alpha)*prior, in integer milli-units.
235	                (LATENCY_ALPHA_MILLI * sample_ms + (1000 - LATENCY_ALPHA_MILLI) * prior) / 1000
236	            };
237	            if self
238	                .ewma_ms
239	                .compare_exchange_weak(prior, next, Ordering::AcqRel, Ordering::Acquire)
240	                .is_ok()
241	            {
242	                return;
243	            }
244	        }
245	    }
246	
247	    /// Current EWMA in ms, or `None` if no sample has been recorded yet.
248	    fn read(&self) -> Option<u64> {
249	        match self.ewma_ms.load(Ordering::Acquire) {
250	            LATENCY_UNSET => None,
251	            v => Some(v),
252	        }
253	    }
254	}
255	
256	/// A lock-free in-flight (outstanding-request) gauge: one `AtomicU64` per
257	/// provider, incremented when an attempt is DISPATCHED and decremented when it
258	/// COMPLETES. Held behind an `Arc` so an [`InFlightGuard`] can own a cheap clone
259	/// and decrement on `Drop` no matter how the attempt exits (success, error, `?`,
260	/// cancellation, or panic-unwind) — the gauge can never leak stuck-high.
261	///
262	/// Read by [`RoutingStrategy::LeastBusy`] to order candidates by fewest
263	/// outstanding requests. Maintained ALWAYS (one relaxed add/sub per attempt),
264	/// but it only AFFECTS ordering under `LeastBusy`; every other strategy ignores
265	/// it, so keeping it current never perturbs their ordering.
266	#[derive(Default)]
267	struct InFlightGauge {
268	    count: AtomicU64,
269	}
270	
271	/// RAII guard returned by [`HealthTracker::enter_in_flight`]. Holds an `Arc` to
272	/// the target provider's gauge; the increment happens at construction, the
273	/// decrement at [`Drop`]. Because `Drop` runs on EVERY exit path of the scope it
274	/// lives in, the in-flight count is balanced even when the provider call returns
275	/// an error, hits `?`, is cancelled (its future dropped), or panics.
276	///
277	/// `#[must_use]`: a guard that is created and immediately dropped would inc then
278	/// dec with no work in between, which is almost always a bug at the call site.
279	#[must_use = "hold the guard for the duration of the provider call; dropping it early decrements the in-flight gauge"]
280	pub struct InFlightGuard {
281	    gauge: Arc<InFlightGauge>,
282	}
283	
284	impl Drop for InFlightGuard {
285	    fn drop(&mut self) {
286	        // Saturating-style: fetch_sub wraps on underflow, but inc/dec are always
287	        // balanced (one guard per attempt), so the count cannot go negative.
288	        self.gauge.count.fetch_sub(1, Ordering::Relaxed);
289	    }
290	}
291	
292	/// Outcome of a HARD-cap probe admission ([`HealthTracker::try_enter_probe`]).
293	pub enum ProbeAdmission {
294	    /// Admitted — hold the [`InFlightGuard`] across the provider call. In HalfOpen
295	    /// the guard IS the reserved probe permit (the gauge slot was taken atomically
296	    /// with the cap check); in Closed it is the ordinary in-flight meter.
297	    Admitted(InFlightGuard),
298	    /// Refused: the breaker is Open, OR HalfOpen with its probe cap already
299	    /// saturated by outstanding trials. The caller must fail over WITHOUT
300	    /// dispatching — this is the load the hard cap sheds.
301	    Rejected,
302	    /// The provider has no registered breaker/gauge (unknown to health). Proceed
303	    /// UNTRACKED, exactly as before the gauge existed — fail-open, byte-identical
304	    /// to the pre-cap `enter_in_flight` returning `None`.
305	    Untracked,
306	}
