308	/// Per-provider health: one circuit breaker plus one latency EWMA plus one
309	/// in-flight gauge per provider, pre-registered at startup so the map is
310	/// read-only (the atomics do all the mutation, so no lock is needed on the
311	/// request path).
312	pub struct HealthTracker {
313	    breakers: HashMap<String, CircuitBreaker>,
314	    latency: HashMap<String, LatencyEwma>,
315	    in_flight: HashMap<String, Arc<InFlightGauge>>,
316	    /// ADR-087 multi-account: per-key rate-limit **cooldown** cells (`cooled_until`
317	    /// epoch-millis; `0` = not cooled). A fixed-size array indexed by
318	    /// `hash(tenant, provider, key_index)`, allocated once — lock-free reads/writes
319	    /// over a single atomic, no dynamic map, no key-registry coupling, nothing to
320	    /// rebuild on a key reload. Cross-tenant correct (tenant is in the hash); a rare
321	    /// hash collision shares a cooldown benignly (a healthy key is briefly skipped,
322	    /// self-heals at expiry — never a wrong-key-used). Distinct from the per-provider
323	    /// `CircuitBreaker` (fault-detection); a cooldown cell cools a key on the FIRST
324	    /// 429 and honors Retry-After.
325	    key_cooldowns: Box<[AtomicU64]>,
326	}
327	
328	/// Number of per-key cooldown cells (power of two so the hash maps with a mask).
329	/// 4096 × 8 B = 32 KiB, allocated once; ample for the handful of `(tenant, provider,
330	/// key)` tuples a deployment holds, so collisions are negligible.
331	const KEY_COOLDOWN_CELLS: usize = 4096;
332	
333	impl HealthTracker {
334	    pub fn new<I, S>(providers: I) -> Self
335	    where
336	        I: IntoIterator<Item = S>,
337	        S: Into<String>,
338	    {
339	        let mut breakers = HashMap::new();
340	        let mut latency = HashMap::new();
341	        let mut in_flight = HashMap::new();
342	        for p in providers {
343	            let name: String = p.into();
344	            breakers.insert(name.clone(), CircuitBreaker::new());
345	            latency.insert(name.clone(), LatencyEwma::new());
346	            in_flight.insert(name, Arc::new(InFlightGauge::default()));
347	        }
348	        let key_cooldowns = (0..KEY_COOLDOWN_CELLS)
349	            .map(|_| AtomicU64::new(0))
350	            .collect::<Vec<_>>()
351	            .into_boxed_slice();
352	        Self {
353	            breakers,
354	            latency,
355	            in_flight,
356	            key_cooldowns,
357	        }
358	    }
359	
360	    pub fn breaker(&self, provider: &str) -> Option<&CircuitBreaker> {
361	        self.breakers.get(provider)
362	    }
363	
364	    /// The per-key cooldown cell for `(tenant, provider, key_index)` (ADR-087).
365	    fn key_cell(&self, tenant: &str, provider: &str, key_index: usize) -> &AtomicU64 {
366	        use std::hash::{Hash, Hasher};
367	        let mut h = std::collections::hash_map::DefaultHasher::new();
368	        tenant.hash(&mut h);
369	        provider.hash(&mut h);
370	        key_index.hash(&mut h);
371	        // KEY_COOLDOWN_CELLS is a power of two, so `& (N-1)` == `% N`.
372	        &self.key_cooldowns[(h.finish() as usize) & (KEY_COOLDOWN_CELLS - 1)]
373	    }
374	
375	    /// Is pool key `key_index` of `(tenant, provider)` available (not cooled down)
376	    /// at `now_ms`? `now_ms` is passed in so the check is pure/testable (no stored
377	    /// clock). A never-cooled key (cell `0`) is always available.
378	    pub fn key_available(
379	        &self,
380	        tenant: &str,
381	        provider: &str,
382	        key_index: usize,
383	        now_ms: u64,
384	    ) -> bool {
385	        self.key_cell(tenant, provider, key_index)
386	            .load(Ordering::Acquire)
387	            <= now_ms
388	    }
389	
390	    /// The `cooled_until` timestamp (epoch ms; `0` = never cooled) for a pool key.
391	    pub fn key_cooled_until(&self, tenant: &str, provider: &str, key_index: usize) -> u64 {
392	        self.key_cell(tenant, provider, key_index)
393	            .load(Ordering::Acquire)
394	    }
395	
396	    /// Cool a pool key until `until_ms` (epoch ms). **Extend-only** (never shortens
397	    /// an existing cooldown), so a transient `5xx` cannot cut short a `401` dead-key
398	    /// window; an expired/absent cooldown (`cell <= until_ms`) is set fresh.
399	    pub fn cool_key(&self, tenant: &str, provider: &str, key_index: usize, until_ms: u64) {
400	        let cell = self.key_cell(tenant, provider, key_index);
401	        let mut cur = cell.load(Ordering::Acquire);
402	        while until_ms > cur {
403	            match cell.compare_exchange_weak(cur, until_ms, Ordering::AcqRel, Ordering::Acquire) {
404	                Ok(_) => break,
405	                Err(observed) => cur = observed,
406	            }
407	        }
408	    }
409	
410	    /// Clear a pool key's cooldown (a success — the key demonstrably works).
411	    pub fn clear_key(&self, tenant: &str, provider: &str, key_index: usize) {
412	        self.key_cell(tenant, provider, key_index)
413	            .store(0, Ordering::Release);
414	    }
415	
416	    /// Record an observed latency sample (milliseconds) for `provider`, folding
417	    /// it into that provider's EWMA. Unknown providers are ignored.
418	    pub fn record_latency(&self, provider: &str, ms: u64) {
419	        if let Some(l) = self.latency.get(provider) {
420	            l.record(ms);
421	        }
422	    }
423	
424	    /// Current latency EWMA (ms) for `provider`, or `None` if no sample has been
425	    /// recorded yet (or the provider is unknown). Used by the `Latency` strategy
426	    /// to order providers and to treat untried ones optimistically.
427	    pub fn latency_ms(&self, provider: &str) -> Option<u64> {
428	        self.latency.get(provider).and_then(|l| l.read())
429	    }
430	
431	    /// Current number of outstanding (in-flight) requests for `provider`. Read by
432	    /// the [`RoutingStrategy::LeastBusy`] ordering. An unknown provider (no gauge
433	    /// registered) reports the maximum so it sorts LAST — least-busy never
434	    /// prefers a provider it cannot meter.
435	    pub fn in_flight(&self, provider: &str) -> u64 {
436	        self.in_flight
437	            .get(provider)
438	            .map(|g| g.count.load(Ordering::Relaxed))
439	            .unwrap_or(u64::MAX)
440	    }
441	
442	    /// Mark an attempt as DISPATCHED to `provider`: increments its in-flight gauge
443	    /// and returns an [`InFlightGuard`] that decrements it on `Drop`. Hold the
444	    /// guard across the provider call so the count is balanced on every exit path
445	    /// (success, error, `?`, cancellation, panic). Returns `None` for an unknown
446	    /// provider (no gauge to track) — the caller proceeds untracked, exactly as
447	    /// before the gauge existed.
448	    pub fn enter_in_flight(&self, provider: &str) -> Option<InFlightGuard> {
449	        let gauge = self.in_flight.get(provider)?.clone();
450	        gauge.count.fetch_add(1, Ordering::Relaxed);
451	        Some(InFlightGuard { gauge })
452	    }
453	
454	    /// Available unless the circuit is Open, OR the breaker is HalfOpen and its
455	    /// probe cap is already saturated by outstanding trials — the half-open
456	    /// concurrency cap ([`CircuitBreaker::admits`]) reuses the live in-flight
457	    /// gauge as the trial counter (in HalfOpen every in-flight request IS a
458	    /// trial, since nothing else dispatches while Open), so it needs no separate
459	    /// permit bookkeeping and can never leak. Unknown providers (no breaker
460	    /// registered) are treated as available.
461	    pub fn is_available(&self, provider: &str) -> bool {
462	        self.breakers
463	            .get(provider)
464	            .map(|b| b.admits(self.in_flight(provider)))
465	            .unwrap_or(true)
466	    }
467	
468	    /// Atomically ADMIT a probe against `provider` **and** reserve its in-flight
469	    /// slot in one operation — the HARD half-open concurrency cap. The
470	    /// [`is_available`](Self::is_available) + [`enter_in_flight`](Self::enter_in_flight)
471	    /// pair a caller would otherwise use leaves a check→dispatch gap: two tasks can
472	    /// each read `in_flight < success_threshold` before either increments the gauge,
473	    /// so a concurrent burst overshoots the cap ([`CircuitBreaker::admits`] documents
474	    /// this softness). Here the threshold check and the gauge increment are one CAS,
475	    /// so at most `success_threshold` trials are ever in flight against a HalfOpen
476	    /// provider. Lock-free (a single atomic gauge, RAII-released on `Drop`); the
477	    /// breaker-state read is a separate load, but a transition racing it is benign
478	    /// and self-correcting (a HalfOpen→Closed race admits one extra; a Closed→HalfOpen
479	    /// race is the same one-instant softness the gauge always had).
480	    pub fn try_enter_probe(&self, provider: &str) -> ProbeAdmission {
481	        let Some(breaker) = self.breakers.get(provider) else {
482	            return ProbeAdmission::Untracked;
483	        };
484	        let gauge = match self.in_flight.get(provider) {
485	            Some(g) => g.clone(),
486	            None => return ProbeAdmission::Untracked,
487	        };
488	        match breaker.state() {
489	            CircuitState::Open => ProbeAdmission::Rejected,
490	            // Closed: admit unconditionally — the probe cap is half-open-only. One
491	            // relaxed add, identical to `enter_in_flight`.
492	            CircuitState::Closed => {
493	                gauge.count.fetch_add(1, Ordering::Relaxed);
494	                ProbeAdmission::Admitted(InFlightGuard { gauge })
495	            }
496	            // HalfOpen: conditional increment. Admit only while fewer than
497	            // `success_threshold` trials are outstanding; the CAS folds the cap
498	            // check and the reservation into one atomic step (no overshoot).
499	            CircuitState::HalfOpen => {
500	                let cap = breaker.success_threshold;
501	                loop {
502	                    let cur = gauge.count.load(Ordering::Acquire);
503	                    if cur >= cap {
504	                        return ProbeAdmission::Rejected;
505	                    }
506	                    if gauge
507	                        .count
508	                        .compare_exchange_weak(cur, cur + 1, Ordering::AcqRel, Ordering::Acquire)
509	                        .is_ok()
510	                    {
511	                        return ProbeAdmission::Admitted(InFlightGuard { gauge });
512	                    }
513	                }
514	            }
515	        }
516	    }
517	
518	    pub fn record_success(&self, provider: &str) {
519	        if let Some(b) = self.breakers.get(provider) {
520	            b.record_success();
521	        }
522	    }
523	
524	    pub fn record_failure(&self, provider: &str) {
525	        if let Some(b) = self.breakers.get(provider) {
526	            b.record_failure();
527	        }
528	    }
529	
530	    pub fn state(&self, provider: &str) -> CircuitState {
531	        self.breakers
532	            .get(provider)
533	            .map(|b| b.state())
534	            .unwrap_or(CircuitState::Closed)
535	    }
536	
537	    /// The registered provider names. The breaker map is built once at startup
538	    /// and never mutated (the atomics do all per-provider mutation), so this is
539	    /// a lock-free read over an immutable structure — safe to call off the hot
540	    /// path (e.g. the read-only `/status` surface). Order is unspecified; the
541	    /// caller sorts for a stable view.
542	    pub fn provider_names(&self) -> Vec<&str> {
543	        self.breakers.keys().map(String::as_str).collect()
544	    }
545	}
