736	    fn try_enter_probe_hard_caps_half_open_concurrency() {
737	        use std::sync::Arc;
738	        // Deterministic clock for the cooldown → half-open transition.
739	        let mut h = HealthTracker::new(["openai"]);
740	        let clock = Arc::new(AtomicU64::new(0));
741	        let c = clock.clone();
742	        // failure_threshold=2, success_threshold=2, cooldown=100ms.
743	        h.breakers.insert(
744	            "openai".to_string(),
745	            CircuitBreaker::with_clock(2, 2, 100, Box::new(move || c.load(Ordering::Relaxed))),
746	        );
747	
748	        // Closed: admits unconditionally (probe cap is half-open-only).
749	        match h.try_enter_probe("openai") {
750	            ProbeAdmission::Admitted(g) => {
751	                assert_eq!(h.in_flight("openai"), 1);
752	                drop(g);
753	                assert_eq!(h.in_flight("openai"), 0);
754	            }
755	            _ => panic!("Closed breaker must admit"),
756	        }
757	
758	        // Unknown provider: Untracked (fail-open), no gauge touched.
759	        assert!(matches!(
760	            h.try_enter_probe("unknown"),
761	            ProbeAdmission::Untracked
762	        ));
763	
764	        // Trip Open — every probe refused.
765	        h.record_failure("openai");
766	        h.record_failure("openai");
767	        assert!(matches!(
768	            h.try_enter_probe("openai"),
769	            ProbeAdmission::Rejected
770	        ));
771	
772	        // Cooldown elapses → HalfOpen. The HARD cap admits at most
773	        // success_threshold (2) trials — reservation is ATOMIC with the check, so
774	        // unlike the soft `is_available` gate there is no check→dispatch overshoot.
775	        clock.store(200, Ordering::Relaxed);
776	        let p1 = match h.try_enter_probe("openai") {
777	            ProbeAdmission::Admitted(g) => g,
778	            _ => panic!("1st half-open probe must be admitted"),
779	        };
780	        let p2 = match h.try_enter_probe("openai") {
781	            ProbeAdmission::Admitted(g) => g,
782	            _ => panic!("2nd half-open probe must be admitted"),
783	        };
784	        assert_eq!(h.in_flight("openai"), 2);
785	        // 3rd probe: cap saturated → Rejected, and the gauge did NOT increment
786	        // (the CAS never fired) — proving the reservation is hard, not soft.
787	        assert!(matches!(
788	            h.try_enter_probe("openai"),
789	            ProbeAdmission::Rejected
790	        ));
791	        assert_eq!(h.in_flight("openai"), 2);
792	        // A trial completes → a permit frees → the next probe is admitted again.
793	        drop(p2);
794	        assert_eq!(h.in_flight("openai"), 1);
795	        let p3 = match h.try_enter_probe("openai") {
796	            ProbeAdmission::Admitted(g) => g,
797	            _ => panic!("probe must be admitted after a permit frees"),
798	        };
799	        assert_eq!(h.in_flight("openai"), 2);
800	        drop(p1);
801	        drop(p3);
802	        assert_eq!(h.in_flight("openai"), 0);
803	    }
